  ('heelevel3-d0d1b9a2-moex-00405', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '下表為某公司按甲法與乙法所求得之存貨資料： 甲 法 乙 法 期初存貨 $130,000 $160,000 期末存貨 $118,000 $145,000 下列何者最有可能為該公司選擇之存貨成本計價方法？', '["甲法為全部成本法，乙法為變動成本法", "甲法為變動成本法，乙法為全部成本法", "甲法為全部成本法，乙法為超變動成本法（throughputcosting；super-variablecosting）", "甲法為變動成本法，乙法為超變動成本法（throughputcosting；super-variablecosting）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "f914331ef9b6", "answer_pdf_sha1": "356cce54f43d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00406', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '甲公司X8年4月份銷貨預算為$500,000，銷售人員的薪資除了每月固定支付$120,000，另根據當 月銷貨金額3%支付績效獎金。甲公司X8年4月份預計銷售人員薪資費用為何？', '["$105,000", "$120,000", "$135,000", "$170,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "f914331ef9b6", "answer_pdf_sha1": "356cce54f43d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00407', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '乙公司預計直接原料購買金額在X1年第一季為$60,000，第二季為$80,000。該公司在購買當季支 付45%的貨款，其餘貨款在下一季支付。乙公司在X1年第二季因購買直接原料而預計的現金支 出為何？', '["$80,000", "$71,000", "$69,000", "$36,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "f914331ef9b6", "answer_pdf_sha1": "356cce54f43d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00408', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '丙公司預計在 X2 年 10 月銷售 100,000 單位產品，並預估往後每個月銷售量均以 10%之比例成 長，每個月期末存貨均設定為下個月預計銷售數量之 70%。丙公司帳上資料顯示，X2 年 9 月底 產品存貨為220,000單位。丙公司應生產多少單位產品才能因應X2年第四季的銷售計畫？', '["111,000 單位", "204,170 單位", "331,000 單位", "424,170 單位"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "f914331ef9b6", "answer_pdf_sha1": "356cce54f43d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00409', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '甲公司售價採製造成本加成百分比計算，若該公司的製造成本加成百分比為毛利率的1.25倍時， 試問該公司的毛利率為何？', '["16.67%", "20%", "25%", "33.33%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "f914331ef9b6", "answer_pdf_sha1": "356cce54f43d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00410', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', 'B公司考慮是否向外購買產品每年所需的組件 10,000 單位，單位售價為$80。若向外購買組件， 固定製造費用可減少60%；且目前用於生產組件的機器可以每年$150,000轉租給其他公司，該機 器成本為$500,000，直線法提列折舊，無殘值，已提列一年折舊$100,000。原自行生產製造產品組 件每單位相關成本包含直接原料$10、直接人工$15、變動製造費用$20以及固定製造費用$30。試 問下列何者正確？', '["應外購，較自製攸關成本節省$80,000", "應外購，較自製攸關成本節省$100,000", "應自製，較外購攸關成本節省$20,000", "應自製，較外購攸關成本節省$100,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "f914331ef9b6", "answer_pdf_sha1": "356cce54f43d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00411', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', 'A公司因應景氣進行組織縮減，擬裁撤甲部門，並將其工作以每月$500,000外包執行。若裁撤甲 部門，將解聘其直接人員，每月薪資為$400,000；間接人員則轉調其他部門，每月薪資維持$50,000。 該部門分攤之公司辦公成本$60,000 則改由其他部門分攤，而其不含折舊之固定成本可減少 $30,000。甲部門設備每月折舊費用為$30,000，若部門裁撤可出租，每月租金$10,000。試問裁撤 甲部門對公司之影響為何？', '["營業利益增加$60,000", "營業利益增加$30,000", "營業利益減少$30,000", "營業利益減少$60,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "f914331ef9b6", "answer_pdf_sha1": "356cce54f43d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00412', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '甲公司投入$100,000購買耐用年數5年的機器設備生產某產品，每年的產量為100個，機器設備 採直線法折舊且無殘值，生產期間每單位變動成本為$400。若甲公司以原始投資金額計算的應計 會計報酬率（accrual accounting rate-of-return）作為投資案之評選方法，且要求報酬率達到8%始 可投資，則在所得稅率20%的環境下，甲公司可接受的最低售價為多少？', '["$500", "$680", "$700", "$7,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "f914331ef9b6", "answer_pdf_sha1": "356cce54f43d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00413', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '某企業投資$2,000,000興建數位3D眼鏡工廠，估計該工廠可使用10年，無殘值，並預期每年銷 售5,000單位，每單位售價$200。若該企業欲每年獲得營業毛利$200,000，則數位3D眼鏡的目標 單位製造成本為何？', '["$120", "$140", "$160", "$180"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "f914331ef9b6", "answer_pdf_sha1": "356cce54f43d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00414', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-111-194ec0d9', 'sub-heelevel3-d0d1b9a2-06', NULL, 'single_choice', '關於平衡計分卡的敘述，下列何者正確？', '["不同企業可能有不同策略，其計分卡之績效指標可能不同", "策略地圖主要在於協助企業找到最適之經營目標", "實施平衡計分卡時，績效指標越多，越能彰顯平衡計分卡之功能", "實施平衡計分卡時，如能獲得資訊系統之輔助，則績效指標越多，越能彰顯平衡計分卡之功能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:01+00:00", "source_pdf_sha1": "f914331ef9b6", "answer_pdf_sha1": "356cce54f43d", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "324", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL)
